DO $$
DECLARE
  d   jsonb := $jdata$[{"slug":"boston-dynamics-spot","name":"Boston Dynamics Spot","manufacturer":"Boston Dynamics","type":"quadruped","introduced_year":2020,"specs_json":{"weight_kg":32.5,"payload_kg":14,"battery_wh":605,"max_speed_ms":1.6,"ip_rating":"IP54","actuator_type":"series elastic actuator (SEA)","compute":"Intel Core i5 (arm computer), dedicated motor controllers","lidar":"optional payload","comms":"Wi-Fi 802.11a/b/g/n/ac, Bluetooth 5.0, payload ethernet","endurance_hours":1.5,"dof":12},"failure_modes":[{"component":"series elastic actuator (SEA) spring pack \u2014 fatigue fracture","symptom":"joint position control becomes sluggish with 20-40ms lag; torque sensing reads erratic; gait contact timing errors logged; robot triggers fall prevention and halts","root_cause":"SEA steel spring pack experiences high-cycle metal fatigue from repeated locomotion impacts; Spot designed for up to 1 million steps \u2014 spring pack fatigue initiates at 500k steps in high-terrain use; fracture renders SEA force sensing unreliable","severity":"critical","mtbf_hours":2000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["actuator","SEA","spring","fatigue","critical","gait"],"repair_protocol":{"title":"SEA Spring Pack Inspection and Module Replacement","steps":[{"step":1,"action":"Power off; engage e-stop; wait 120 seconds for all actuators to discharge stored spring energy","tool":null,"warning":"SEA actuators store mechanical energy in compressed springs \u2014 never disassemble under load or immediately after power-off"},{"step":2,"action":"Position robot on padded work stand in standing configuration at working height; support each leg with foam blocks to unload joints","tool":"padded work stand, foam blocks"},{"step":3,"action":"Remove leg outer shell panels per Boston Dynamics service manual; expose SEA housing","tool":"T10 Torx, T20 Torx, 3mm hex"},{"step":4,"action":"Connect Spot tablet/laptop to robot API; run actuator diagnostics \u2014 `spring_deflection_variance` > 0.8mm RMS indicates spring pack fatigue","tool":"Boston Dynamics Spot API (Python SDK), laptop"},{"step":5,"action":"If spring pack fatigue confirmed: remove SEA module (6x M5 bolts); weigh and log serial number","tool":"4mm hex wrench, digital scale"},{"step":6,"action":"Install factory-refurbished SEA module from Boston Dynamics spare parts program; align spline shaft carefully","tool":"4mm hex wrench","warning":"Boston Dynamics does not support field spring-pack-level repair \u2014 full SEA module swap only"},{"step":7,"action":"Torque M5 bolts to 8.0 Nm in star pattern; reconnect SEA CAN connector","tool":"torque wrench 0-20 Nm"},{"step":8,"action":"Run Boston Dynamics commissioning script via API; verify `spring_deflection_variance` < 0.3mm RMS; perform 100-step gait trial","tool":"Boston Dynamics API, laptop"}],"tools_required":["T10 Torx","T20 Torx","3mm hex","4mm hex wrench","torque wrench 0-20 Nm","laptop with Boston Dynamics Spot API","foam blocks","padded work stand"],"parts":[{"part_name":"Boston Dynamics Spot SEA Module (factory refurbished)","part_number":"BD-SPOT-SEA-FR","supplier":"Boston Dynamics Authorized Service","unit_cost_usd":2200,"qty":1}],"labor_minutes":180,"skill_level":"specialist","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"sea_spring_deflection_variance_mm","signal_source":"SEA encoder via CAN bus","threshold_value":0.6,"threshold_operator":">","threshold_unit":"millimeters RMS","lead_time_hours":72,"confidence":0.75},{"signal_name":"joint_contact_timing_error_ms","signal_source":"locomotion controller log","threshold_value":15,"threshold_operator":">","threshold_unit":"milliseconds","lead_time_hours":48,"confidence":0.7},{"signal_name":"cumulative_step_count","signal_source":"robot operations log","threshold_value":500000,"threshold_operator":">","threshold_unit":"steps","lead_time_hours":168,"confidence":0.8}]},{"component":"605Wh battery pack \u2014 cell degradation and connector erosion","symptom":"runtime drops below 45 minutes; docking station reports charge fault; battery LED shows orange (fault); CLI `battery info` shows SOH < 70%","root_cause":"lithium cells degrade faster under repeated partial-discharge cycles during multi-shift operation without full charge cycles; battery dock contact pins experience arcing erosion from repeated mate/demate under partial charge residual current","severity":"high","mtbf_hours":1500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","electrical","connector","SOH","dock"],"repair_protocol":{"title":"Spot Battery Pack and Dock Contact Replacement","steps":[{"step":1,"action":"Log battery SOH via robot SDK: `robot_state.power_state.locomotion_charge_percentage` and battery info endpoint","tool":"Boston Dynamics Spot Python SDK"},{"step":2,"action":"Inspect dock contact pins (4-pin, gold-plated) for pitting or blackening; inspect matching battery receptacle","tool":"magnifying glass, flashlight"},{"step":3,"action":"Clean dock pins with contact cleaner and cotton swab; if pitting depth > 0.5mm, replace dock contact assembly","tool":"DeoxIT D5 contact cleaner, cotton swab, vernier calipers"},{"step":4,"action":"Press battery release on robot side; slide battery out of bay; install new OEM battery","tool":null},{"step":5,"action":"Perform 3 full charge cycles (0-100%) to condition new cells; verify SOH > 95% after conditioning","tool":"Spot dock, SDK battery monitor"},{"step":6,"action":"Dispose of old battery per Boston Dynamics battery return program; do not landfill","tool":null}],"tools_required":["Boston Dynamics Spot Python SDK","magnifying glass","DeoxIT D5 contact cleaner","cotton swabs","vernier calipers"],"parts":[{"part_name":"Boston Dynamics Spot Battery (605Wh)","part_number":"BD-SPOT-BATT-605","supplier":"Boston Dynamics Official Store","unit_cost_usd":1800,"qty":1},{"part_name":"Spot Dock Contact Assembly","part_number":"BD-SPOT-DOCK-CONTACT","supplier":"Boston Dynamics Authorized Service","unit_cost_usd":280,"qty":1}],"labor_minutes":30,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"battery_soh_pct","signal_source":"Spot SDK power_state","threshold_value":75,"threshold_operator":"<","threshold_unit":"percent","lead_time_hours":168,"confidence":0.88},{"signal_name":"runtime_minutes","signal_source":"operations log","threshold_value":60,"threshold_operator":"<","threshold_unit":"minutes per charge","lead_time_hours":48,"confidence":0.82}]},{"component":"IP54 hip panel seal \u2014 degradation from cleaning agent exposure","symptom":"internal moisture alarm; corrosion on payload bay connector pins; IP54 rating compromised after industrial environment deployment","root_cause":"Spot deployed in industrial inspection environments uses harsh cleaning agents (degreasers, alkaline foam cleaners) for decontamination; some agents degrade EPDM panel gaskets and silicone RTV seals faster than water alone","severity":"medium","mtbf_hours":3000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sealing","IP54","chemical","corrosion","industrial"],"repair_protocol":{"title":"Hip Panel IP54 Gasket Replacement and Corrosion Treatment","steps":[{"step":1,"action":"Power off; remove all payload equipment; remove hip panels per Boston Dynamics service guide (T20 Torx, 12 screws)","tool":"T20 Torx screwdriver"},{"step":2,"action":"Inspect all gaskets and RTV beads for chemical attack (swelling, crumbling, discoloration)","tool":"inspection light, magnifying glass"},{"step":3,"action":"Remove all degraded gasket material; clean channels with IPA","tool":"IPA, plastic scraper, lint-free cloth"},{"step":4,"action":"Treat any corrosion on connector pins with DeoxIT D5; dry with compressed air","tool":"DeoxIT D5, compressed air","warning":"Do not use isopropyl alcohol on gold connector pins \u2014 causes micro-pitting"},{"step":5,"action":"Install new silicone gasket tape rated for chemical resistance (EPDM or PTFE-backed); press firmly into groove","tool":"PTFE or EPDM gasket tape"},{"step":6,"action":"Apply thin bead of chemical-resistant RTV (Dow Corning 736 Heat Resistant Sealant) to seam areas","tool":"Dow Corning 736 RTV, applicator"},{"step":7,"action":"Reinstall panels; torque T20 screws to 2.5 Nm; perform water spray test; monitor humidity sensor < 60% RH","tool":"torque wrench, garden hose spray nozzle, SDK humidity monitor"}],"tools_required":["T20 Torx","torque wrench","IPA","DeoxIT D5","PTFE gasket tape","Dow Corning 736 RTV","compressed air","garden hose"],"parts":[{"part_name":"PTFE-Backed Self-Adhesive Gasket Tape 8mm x 2mm x 3m","part_number":"PTFE-8X2-3M","supplier":"RS Components","unit_cost_usd":18,"qty":2},{"part_name":"Dow Corning 736 Heat Resistant Sealant 90g","part_number":"DC-736-90G","supplier":"Dow Corning / Dupont","unit_cost_usd":24,"qty":1}],"labor_minutes":75,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"internal_humidity_rh_pct","signal_source":"Spot internal humidity sensor","threshold_value":65,"threshold_operator":">","threshold_unit":"percent RH","lead_time_hours":12,"confidence":0.8},{"signal_name":"days_since_last_gasket_service","signal_source":"maintenance log","threshold_value":180,"threshold_operator":">","threshold_unit":"days","lead_time_hours":168,"confidence":0.75}]},{"component":"motor controller board \u2014 thermal derating from blocked airflow","symptom":"robot reduces gait speed automatically; SDK reports motor_temp_warning on 1-2 legs; performance restoration after 5-minute rest period","root_cause":"Spot motor controllers rely on passive conduction cooling through leg housing; dust, mud, or debris buildup on external housing surface reduces thermal conductivity; controller reduces maximum torque output to protect electronics","severity":"medium","mtbf_hours":500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["thermal","motor-controller","cooling","debris","maintenance"],"repair_protocol":{"title":"Motor Controller Housing External Thermal Surface Cleaning","steps":[{"step":1,"action":"Power off; allow 10-minute cool-down; inspect all leg housing external surfaces for mud or debris buildup","tool":"flashlight"},{"step":2,"action":"Use stiff nylon brush to loosen dried mud/debris from heat dissipation fins and housing ribs","tool":"stiff nylon brush"},{"step":3,"action":"Wipe all surfaces with damp cloth; dry with compressed air blast","tool":"damp cloth, compressed air","warning":"Do not aim compressed air at joint seals \u2014 may force debris past IP54 gaskets"},{"step":4,"action":"Power on; run 10-minute walk; verify motor temp stays < 60C via SDK temp readings","tool":"laptop with Spot SDK, open environment"},{"step":5,"action":"If thermal issue persists after cleaning, apply thin layer of Fujipoly XR-m gap filler between motor controller and housing wall","tool":"Fujipoly XR-m thermal gap pad, plastic scraper"}],"tools_required":["nylon brush","compressed air","damp cloth","laptop with Spot SDK"],"parts":[{"part_name":"Fujipoly XR-m Thermal Gap Filler 100x100x1mm","part_number":"FUJIPOLY-XRM-1MM","supplier":"Fujipoly / Digi-Key","unit_cost_usd":28,"qty":2}],"labor_minutes":25,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"motor_temp_c_max_leg","signal_source":"Spot SDK robot_state motor_temperatures","threshold_value":58,"threshold_operator":">","threshold_unit":"celsius","lead_time_hours":2,"confidence":0.82},{"signal_name":"gait_speed_reduction_pct","signal_source":"locomotion controller log","threshold_value":20,"threshold_operator":">","threshold_unit":"percent below commanded speed","lead_time_hours":1,"confidence":0.78}]},{"component":"foot rubber pad \u2014 wear and delamination","symptom":"traction loss on smooth or wet surfaces; robot slips during direction changes; increased fall protection interventions; foot pad visually worn or delaminated","root_cause":"foot rubber pads rated for ~1 million steps on typical mixed-terrain; concrete, asphalt, and industrial tile surfaces wear pads 3-5x faster; worn pads expose plastic foot structure causing coefficient of friction drop from 0.8 to 0.3","severity":"medium","mtbf_hours":400,"source_urls":["unverified-training-data"],"confidence":"low","tags":["foot","wear","traction","safety","maintenance"],"repair_protocol":{"title":"Spot Foot Rubber Pad Replacement","steps":[{"step":1,"action":"Measure rubber pad center thickness with calipers \u2014 replace at < 4mm remaining (nominal 12mm)","tool":"vernier calipers"},{"step":2,"action":"Remove foot from leg: remove 3x M4 foot-to-lower-leg bolts; disconnect foot (no internal connectors on standard foot)","tool":"3mm hex wrench"},{"step":3,"action":"Peel old rubber pad from foot structure; clean bonding surface with IPA","tool":"plastic pry, IPA, abrasive pad"},{"step":4,"action":"Apply Loctite 480 rubber bonding adhesive to foot structure; press new pad; clamp for 2 hours","tool":"Loctite 480, C-clamp, wax paper"},{"step":5,"action":"Reinstall foot to leg; torque M4 bolts to 4.0 Nm","tool":"3mm hex wrench, torque wrench 0-10 Nm"},{"step":6,"action":"Run 5-minute walk trial on hard surface; verify no slipping during sharp turns","tool":"open hard surface area"}],"tools_required":["vernier calipers","3mm hex wrench","torque wrench 0-10 Nm","Loctite 480","C-clamp","IPA"],"parts":[{"part_name":"Boston Dynamics Spot Foot Rubber Pad Set (4x)","part_number":"BD-SPOT-FOOT-PAD-4PK","supplier":"Boston Dynamics Official Store","unit_cost_usd":120,"qty":1}],"labor_minutes":60,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"foot_pad_thickness_mm","signal_source":"manual inspection log","threshold_value":5,"threshold_operator":"<","threshold_unit":"millimeters","lead_time_hours":48,"confidence":0.88},{"signal_name":"slip_event_count_per_hour","signal_source":"fall prevention controller log","threshold_value":3,"threshold_operator":">","threshold_unit":"events per hour","lead_time_hours":12,"confidence":0.78}]},{"component":"Spot Core payload computer \u2014 NVMe SSD endurance","symptom":"Spot Core fails to boot; user payload apps unavailable; SSH connection timeout; Core LED shows error pattern","root_cause":"NVMe SSD write endurance exhausted from continuous payload application log writing; Spot Core Intel NUC-based compute logs at high rate during inspection missions; M.2 SSD rated 150TBW exceeded after 18-24 months of daily use","severity":"high","mtbf_hours":8760,"source_urls":["unverified-training-data"],"confidence":"low","tags":["compute","storage","payload","Spot-Core","NVMe"],"repair_protocol":{"title":"Spot Core NVMe SSD Replacement","steps":[{"step":1,"action":"Remove Spot Core from payload bay (4x M4 captive bolts); disconnect Ethernet and power cable","tool":"3mm hex wrench"},{"step":2,"action":"Open Spot Core enclosure per service guide (6x T8 Torx screws)","tool":"T8 Torx"},{"step":3,"action":"Remove M.2 2280 NVMe SSD (single M2 screw); install new Samsung 990 Pro 1TB M.2 NVMe","tool":"JIS #0 screwdriver"},{"step":4,"action":"Restore Spot Core OS from USB recovery image; follow Boston Dynamics Spot Core restore procedure","tool":"USB-A recovery drive, monitor/keyboard via HDMI"},{"step":5,"action":"Configure log rotation limits; verify SSD SMART health shows available_spare > 90%; reinstall Core to robot","tool":"SSH terminal, nvme-cli"}],"tools_required":["3mm hex wrench","T8 Torx","JIS #0 screwdriver","USB recovery drive","SSH terminal"],"parts":[{"part_name":"Samsung 990 Pro 1TB M.2 2280 NVMe SSD","part_number":"MZ-V9P1T0B/AM","supplier":"Samsung / Amazon / CDW","unit_cost_usd":95,"qty":1}],"labor_minutes":60,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"ssd_available_spare_pct","signal_source":"Spot Core nvme-cli SMART","threshold_value":10,"threshold_operator":"<","threshold_unit":"percent","lead_time_hours":168,"confidence":0.88},{"signal_name":"ssd_percentage_used_pct","signal_source":"Spot Core nvme-cli SMART","threshold_value":85,"threshold_operator":">","threshold_unit":"percent lifetime used","lead_time_hours":336,"confidence":0.85}]},{"component":"wrist / gripper attachment interface \u2014 electrical contact fouling","symptom":"gripper payload loses power intermittently; payload detection fails; SDK shows payload not authenticated; gripper opens unexpectedly mid-task","root_cause":"Spot payload port uses spring-loaded pogo pin contacts for power and data; industrial environments deposit conductive dust and moisture on pogo pins and mating PCB pads; contact resistance rises above authentication threshold","severity":"high","mtbf_hours":500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["payload","gripper","electrical","contact","fouling"],"repair_protocol":{"title":"Spot Gripper/Payload Pogo Pin Contact Cleaning","steps":[{"step":1,"action":"Power off robot; remove gripper from wrist payload port","tool":null},{"step":2,"action":"Inspect wrist pogo pins (12-pin array) and gripper mating pads under magnification; look for oxidation or debris","tool":"magnifying glass, flashlight"},{"step":3,"action":"Apply 1-2 drops DeoxIT D5 to pogo pin contact surface; mate and demate gripper 10x to burnish contacts","tool":"DeoxIT D5 contact cleaner"},{"step":4,"action":"Dry with compressed air; wipe mating pads on gripper with IPA-dampened cotton swab","tool":"compressed air, IPA, cotton swab"},{"step":5,"action":"Reattach gripper; power on; verify payload authentication succeeds; run grip/open 20 cycles via tablet app","tool":"Boston Dynamics tablet controller"},{"step":6,"action":"If contact resistance still high after cleaning, inspect pogo pin spring tension \u2014 replace pogo pin block if spring force < 50g measured with spring scale","tool":"spring scale, pogo pin replacement block"}],"tools_required":["magnifying glass","DeoxIT D5","compressed air","IPA","cotton swabs","spring scale","Boston Dynamics tablet"],"parts":[{"part_name":"Boston Dynamics Spot Wrist Pogo Pin Contact Block","part_number":"BD-SPOT-WRIST-POGO","supplier":"Boston Dynamics Authorized Service","unit_cost_usd":180,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"payload_auth_fail_count","signal_source":"Spot SDK payload authentication log","threshold_value":2,"threshold_operator":">","threshold_unit":"failures per session","lead_time_hours":6,"confidence":0.85},{"signal_name":"gripper_power_interrupt_count","signal_source":"gripper controller log","threshold_value":1,"threshold_operator":">","threshold_unit":"events per mission","lead_time_hours":4,"confidence":0.8}]},{"component":"front stereo camera pair \u2014 calibration drift from thermal shock","symptom":"3D vision obstacle detection range reduces from 5m to 2m; robot takes wider berth around obstacles than commanded; navigation errors in tight spaces","root_cause":"Spot front stereo cameras require sub-pixel calibration for accurate depth estimation; rapid temperature changes (indoor/outdoor transitions in winter) cause aluminum camera bracket thermal expansion mismatch with camera module, shifting stereo baseline by 50-100 microns \u2014 sufficient to corrupt depth accuracy","severity":"medium","mtbf_hours":2000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sensor","camera","calibration","thermal","stereo-vision","navigation"],"repair_protocol":{"title":"Front Stereo Camera Recalibration","steps":[{"step":1,"action":"Allow robot to equilibrate to ambient temperature for 30 minutes before calibration \u2014 never calibrate immediately after temperature transition","tool":null},{"step":2,"action":"Set up Boston Dynamics stereo calibration target (1m x 1m checkerboard) at 2m from robot in consistent lighting","tool":"Boston Dynamics calibration checkerboard, even lighting"},{"step":3,"action":"Connect laptop to robot via Wi-Fi; run calibration tool via Spot SDK: `bosdyn.client.image_service` calibration routine","tool":"laptop with Spot SDK"},{"step":4,"action":"Follow SDK calibration wizard \u2014 capture 15-20 positions; wizard will reject positions with insufficient baseline variation","tool":"Boston Dynamics tablet or laptop"},{"step":5,"action":"Apply new calibration; verify obstacle detection range > 4.5m on 100mm calibration target","tool":"Spot SDK depth verification script, measuring tape"}],"tools_required":["Boston Dynamics stereo calibration checkerboard","laptop with Spot SDK","measuring tape","consistent lighting setup"],"parts":[],"labor_minutes":45,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"stereo_depth_max_range_m","signal_source":"vision perception diagnostics","threshold_value":3.5,"threshold_operator":"<","threshold_unit":"meters","lead_time_hours":8,"confidence":0.72},{"signal_name":"indoor_outdoor_transition_count","signal_source":"mission log","threshold_value":20,"threshold_operator":">","threshold_unit":"transitions since last calibration","lead_time_hours":48,"confidence":0.65}]}],"suppliers":[{"name":"Boston Dynamics Authorized Service","website":"https://bostondynamics.com","region":"NA","component_types":["SEA module","battery","pogo pin block","service parts"],"lead_time_days":14,"risk_level":"high","notes":"Official parts only \u2014 no third-party SEA modules supported"},{"name":"Boston Dynamics Official Store","website":"https://bostondynamics.com/store","region":"NA","component_types":["battery","foot pad","accessories"],"lead_time_days":7,"risk_level":"medium"},{"name":"RS Components","website":"https://uk.rs-online.com","region":"EU","component_types":["gasket tape","fasteners","general electronics"],"lead_time_days":3,"risk_level":"low"}],"research_sources":["unverified-training-data"]}]$jdata$::jsonb;
  p   jsonb;
  fm  jsonb;
  sig jsonb;
  pid  uuid;
  fmid uuid;
BEGIN
  FOR p IN SELECT value FROM jsonb_array_elements(d)
  LOOP
    SELECT id INTO pid FROM platforms WHERE slug = p->>'slug';
    IF pid IS NULL THEN
      INSERT INTO platforms (slug,name,manufacturer,type,introduced_year,specs_json,techmedix_status)
      VALUES (p->>'slug',p->>'name',p->>'manufacturer',p->>'type',
              NULLIF(p->>'introduced_year','null')::integer,
              COALESCE(p->'specs_json','{}'::jsonb),'supported')
      RETURNING id INTO pid;
    END IF;
    FOR fm IN SELECT value FROM jsonb_array_elements(p->'failure_modes')
    LOOP
      INSERT INTO failure_modes (platform_id,component,symptom,root_cause,severity,mtbf_hours,source_urls,confidence,tags)
      VALUES (pid, fm->>'component', fm->>'symptom', fm->>'root_cause',
              COALESCE(fm->>'severity','medium'),
              NULLIF(fm->>'mtbf_hours','null')::integer,
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'source_urls','["unverified-training-data"]'::jsonb))),
              COALESCE(fm->>'confidence','low'),
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'tags','[]'::jsonb))))
      ON CONFLICT (platform_id,component,symptom) DO UPDATE SET severity=EXCLUDED.severity, updated_at=now()
      RETURNING id INTO fmid;
      IF fm ? 'repair_protocol' THEN
        INSERT INTO repair_protocols (failure_mode_id,title,steps_json,tools_required,parts_json,labor_minutes,skill_level,source_url,verified_by,version)
        SELECT fmid,
               fm->'repair_protocol'->>'title',
               COALESCE(fm->'repair_protocol'->'steps','[]'::jsonb),
               ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'repair_protocol'->'tools_required','[]'::jsonb))),
               COALESCE(fm->'repair_protocol'->'parts','[]'::jsonb),
               NULLIF(fm->'repair_protocol'->>'labor_minutes','null')::integer,
               COALESCE(fm->'repair_protocol'->>'skill_level','intermediate'),
               fm->'repair_protocol'->>'source_url',
               'research_agent', 1
        WHERE NOT EXISTS (SELECT 1 FROM repair_protocols WHERE failure_mode_id=fmid);
      END IF;
      FOR sig IN SELECT value FROM jsonb_array_elements(COALESCE(fm->'predictive_signals','[]'::jsonb))
      LOOP
        INSERT INTO predictive_signals (failure_mode_id,signal_name,signal_source,threshold_value,threshold_operator,threshold_unit,lead_time_hours,confidence,notes)
        SELECT fmid, sig->>'signal_name', sig->>'signal_source',
               NULLIF(sig->>'threshold_value','null')::numeric,
               COALESCE(sig->>'threshold_operator','>'),
               sig->>'threshold_unit',
               NULLIF(sig->>'lead_time_hours','null')::integer,
               NULLIF(sig->>'confidence','null')::numeric,
               sig->>'notes'
        WHERE NOT EXISTS (SELECT 1 FROM predictive_signals WHERE failure_mode_id=fmid AND signal_name=sig->>'signal_name');
      END LOOP;
    END LOOP;
  END LOOP;
END $$;